import React from 'react';

function DeviceMockups({ screenshots = {} }) {
  const {
    laptop = '/images/dashboard-screenshot.png',
    phone = '/images/app-screenshot.png',
    tablet = '/images/tablet-screenshot.png'
  } = screenshots;

  return (
    <div className="relative w-full h-full flex items-center justify-center">
      {/* Laptop */}
      <div className="relative z-10">
        <div className="relative">
          {/* Laptop frame */}
          <div className="w-[400px] h-[250px] bg-gray-900 rounded-t-xl p-2 shadow-2xl">
            <div className="w-full h-full bg-gray-800 rounded-lg overflow-hidden">
              <img 
                src={laptop} 
                alt="Dashboard" 
                className="w-full h-full object-cover"
                onError={(e) => {
                  e.target.style.display = 'none';
                  e.target.parentElement.innerHTML = '<div class="w-full h-full bg-gradient-to-br from-blue-600 to-purple-600 flex items-center justify-center text-white text-sm">Dashboard Preview</div>';
                }}
              />
            </div>
          </div>
          {/* Laptop base */}
          <div className="w-[440px] h-4 bg-gradient-to-b from-gray-700 to-gray-800 rounded-b-xl mx-auto relative -left-5"></div>
          <div className="w-[480px] h-2 bg-gray-800 rounded-b-lg mx-auto relative -left-10 shadow-xl"></div>
        </div>
      </div>

      {/* Phone - right side */}
      <div className="absolute right-0 bottom-0 z-20 transform translate-x-10 translate-y-5">
        <div className="relative">
          {/* Phone frame */}
          <div className="w-[140px] h-[280px] bg-gray-900 rounded-[2rem] p-2 shadow-2xl border-4 border-gray-800">
            {/* Notch */}
            <div className="absolute top-4 left-1/2 transform -translate-x-1/2 w-16 h-5 bg-black rounded-full z-10"></div>
            <div className="w-full h-full bg-gray-800 rounded-[1.5rem] overflow-hidden">
              <img 
                src={phone} 
                alt="Mobile App" 
                className="w-full h-full object-cover"
                onError={(e) => {
                  e.target.style.display = 'none';
                  e.target.parentElement.innerHTML = '<div class="w-full h-full bg-gradient-to-br from-emerald-500 to-cyan-500 flex items-center justify-center text-white text-xs p-4 text-center">Mobile App</div>';
                }}
              />
            </div>
          </div>
        </div>
      </div>

      {/* Tablet - left side */}
      <div className="absolute left-0 top-10 z-5 transform -translate-x-16 -rotate-6">
        <div className="relative opacity-80">
          {/* Tablet frame */}
          <div className="w-[180px] h-[240px] bg-gray-900 rounded-2xl p-2 shadow-xl border-2 border-gray-800">
            <div className="w-full h-full bg-gray-800 rounded-xl overflow-hidden">
              <img 
                src={tablet} 
                alt="Tablet View" 
                className="w-full h-full object-cover"
                onError={(e) => {
                  e.target.style.display = 'none';
                  e.target.parentElement.innerHTML = '<div class="w-full h-full bg-gradient-to-br from-orange-500 to-pink-500 flex items-center justify-center text-white text-xs">Tablet</div>';
                }}
              />
            </div>
          </div>
        </div>
      </div>

      {/* Floating elements */}
      <div className="absolute top-5 right-20 w-12 h-12 bg-emerald-500/20 rounded-full blur-xl animate-pulse"></div>
      <div className="absolute bottom-10 left-10 w-16 h-16 bg-cyan-500/20 rounded-full blur-xl animate-pulse delay-700"></div>
    </div>
  );
}

export default DeviceMockups;
